    "sessionOverview": "Learn how metals are arranged by reactivity, how they displace each other in solutions, and why some are extracted using electricity while others use heat.",
    "introduction": "Have you ever wondered why gold is found as a shiny nugget in rivers, but sodium is never found alone? The answer lies in the 'Reactivity Series'!",
    "learningObjectives": [
      "List the reactivity series of metals.",
      "Predict displacement reactions.",
      "Explain metal extraction methods."
    ],
    "quickRecall": [
      "What is a chemical reaction?",
      "What is an ion?"
    ],
    "easyToRemember": [
      "KING SNAKE: Potassium, Sodium, Calcium, Magnesium, Aluminum, Zinc, Iron, Lead, Hydrogen, Copper, Silver, Gold."
    ],
    "comparisonTables": [
      {
        "title": "Metals vs. Non-Metals",
        "headers": [
          "Feature",
          "Metals",
          "Non-Metals"
        ],
        "rows": [
          [
            "Electron behavior",
            "Lose electrons (Positive ions)",
            "Gain electrons (Negative ions)"
          ],
          [
            "Reactivity with Oxygen",
            "Form basic oxides",
            "Form acidic/neutral oxides"
          ]
        ]
      }
    ],
    "formulaCards": [
      {
        "title": "Displacement Reaction Formula",
        "formula": {
          "text": "Metal A + Salt of Metal B -> Salt of Metal A + Metal B",
          "latex": "A + BC \\rightarrow AC + B"
        },
        "meaning": "If Metal A is more reactive than Metal B, it takes its place.",
        "whenToUse": "When predicting if a reaction will occur between a metal and a salt solution."
      }
    ],
    "geometryDiagrams": [
      {
        "id": "reactivity-ladder",
        "type": "ladder",
