        "points": [],
        "lines": [],
        "arcs": [],
        "labels": [],
        "measurements": []
      }
    ],
    "proofSteps": [
      "Identify the position of both metals in the series.",
      "Check if the free metal is higher than the metal in the salt.",
      "If yes, reaction occurs; if no, no reaction."
    ],
    "commonMistakes": [
      {
        "mistake": "Thinking all metals react with water.",
        "correction": "Only K, Na, Ca react with cold water. Fe reacts only with steam.",
        "example": "Iron nail in water -> No reaction (unless rusted over time)."
      }
    ],
    "sections": [
      {
        "heading": "The Reactivity Series",
        "explanation": "Metals are arranged in a sequence based on how easily they lose electrons. The top metals are very reactive; the bottom ones are less reactive.",
        "keyPoints": [
          "Potassium (K) is the most reactive.",
          "Gold (Au) is the least reactive.",
          "Hydrogen (H) is included as a reference."
        ],
